// ValidateRememberFactRequestBody runs the validations defined on
// RememberFactRequestBody
func ValidateRememberFactRequestBody(body *RememberFactRequestBody) (err error) {
	if body.Kind == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("kind", "body"))
	}
	if body.Content == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("content", "body"))
	}
	if body.Kind != nil {
		if !(*body.Kind == "fact" || *body.Kind == "playbook" || *body.Kind == "glossary" || *body.Kind == "finding") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.kind", *body.Kind, []any{"fact", "playbook", "glossary", "finding"}))
		}
	}
	return
}

